from flask import Flask, request, jsonify

app = Flask(__name__)

users = {
    "user1": {"password": "password1", "mfa_enabled": True, "otp": "123456"},
    "user2": {"password": "password2", "mfa_enabled": False}
}

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if username in users and users[username]['password'] == password:
        if users[username]['mfa_enabled']:
            return jsonify({"message": "Enter OTP"})
        else:
            return jsonify({"message": "Login successful"})
    else:
        return jsonify({"message": "Invalid credentials"})

@app.route('/verify-otp', methods=['POST'])
def verify_otp():
    data = request.get_json()
    username = data.get('username')
    otp = data.get('otp')
    
    if username in users and users[username]['otp'] == otp:
        return jsonify({"message": "Login successful"})
    else:
        return jsonify({"message": "Invalid OTP"})

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if username in users and users[username]['password'] == password:
        return jsonify({"message": "Login successful for API client"})
    else:
        return jsonify({"message": "Invalid credentials for API client"})

if __name__ == '__main__':
    app.run()